// Expected input fields:
// - chat_id: number | number[] | null (null = broadcast to all authorized users)
// - message: string (Telegram Markdown)
// - project_id: string | null
// - event_type: string (project_created | agent_done | build_pass | build_fail | deployed | qa_pass | qa_fail | improvement | error)
// - approval_type: string | null (deploy | start_development | structural_change | improvement)
// - entity_id: string | null (UUID of project/deployment/task)
// - entity_type: string | null
// - disable_notification: boolean

const input = $input.first().json;
const allowedUsers = ($env.TELEGRAM_ALLOWED_USERS || '').split(',').map(s => parseInt(s.trim())).filter(Boolean);
const adminChatId = parseInt($env.TELEGRAM_ADMIN_CHAT_ID || '0');

let chatIds = [];
if (input.chat_id) {
  chatIds = Array.isArray(input.chat_id) ? input.chat_id : [input.chat_id];
} else {
  // Broadcast to all authorized users
  chatIds = allowedUsers.length > 0 ? allowedUsers : (adminChatId ? [adminChatId] : []);
}

if (chatIds.length === 0) {
  return [{ json: { skip: true, reason: 'No target chat IDs configured' } }];
}

const hasApproval = !!(input.approval_type && input.entity_id);

return [{
  json: {
    chat_ids: chatIds,
    message: input.message || '',
    project_id: input.project_id || null,
    event_type: input.event_type || 'info',
    approval_type: input.approval_type || null,
    entity_id: input.entity_id || null,
    entity_type: input.entity_type || 'project',
    has_approval: hasApproval,
    disable_notification: input.disable_notification || false,
    context: input.context || {}
  }
}];

// Build approval record for each chat_id
const params = $input.first().json;
const records = [];

for (const chatId of params.chat_ids) {
  const callbackBase = `${params.approval_type}:${params.entity_id}:${chatId}:${Date.now()}`;
  records.push({
    chat_id: chatId,
    approval_type: params.approval_type,
    entity_id: params.entity_id,
    entity_type: params.entity_type,
    callback_data: callbackBase,
    context: params.context,
    expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString()
  });
}

return records.map(r => ({ json: { ...params, approval_record: r, target_chat_id: r.chat_id, callback_base: r.callback_data } }));

const prev = $('Build Approval Records').first().json;
const approvalRow = $input.first().json[0] || {};
const chatId = prev.target_chat_id;
const callbackBase = prev.callback_base;

const inlineKeyboard = {
  inline_keyboard: [
    [
      { text: '✅ APROBAR', callback_data: `approve:${callbackBase}` },
      { text: '❌ RECHAZAR', callback_data: `reject:${callbackBase}` },
      { text: '⏸ POSPONER', callback_data: `postpone:${callbackBase}` }
    ]
  ]
};

return [{
  json: {
    ...prev,
    target_chat_id: chatId,
    final_message: prev.message,
    reply_markup: inlineKeyboard,
    approval_id: approvalRow.id
  }
}];

// No approval — just map each chat_id to a send target
const params = $input.first().json;
return params.chat_ids.map(chatId => ({
  json: {
    ...params,
    target_chat_id: chatId,
    final_message: params.message,
    reply_markup: null
  }
}));

const sendResult = $input.first().json;
const sentMessage = sendResult.body?.result || sendResult.result || {};
const params = $('Build Inline Keyboard').first()?.json || $('Map to Chat IDs').first()?.json || {};

return [{
  json: {
    chat_id: params.target_chat_id,
    project_id: params.project_id || null,
    event_type: params.event_type || 'info',
    message_id: sentMessage.message_id || null,
    message_text: (params.final_message || '').slice(0, 500)
  }
}];
